import{_ as p}from"./nyalra_kb-7135827b.js";import{_ as l}from"./nyalra_no_mono-8344e451.js";import{_ as s,W as c,X as _,Y as i,Z as e,$ as t,a1 as o,a2 as m,a0 as d,C as a}from"./framework-91490e6a.js";const f={},k=e("figure",null,[e("img",{src:p,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),u={href:"https://tree-novel.com/works/episode/f218151073c8d8dcb95d555fab2256af.html",target:"_blank",rel:"noopener noreferrer"},h=e("p",null,"这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。",-1),b=d('<hr><p>据说「梦」 的内容经常会受到在睡觉时无意识嗅到的气味的影响。这是我在网上看到的。我不知道来源，也没有实际感受。因为我天生患有疾病，没有嗅觉。</p><p>因此，对我来说，梦不可能受到入眠时周围气味的影响。反过来说，对健康的人来说，如果他们在入睡前点燃了香薰，那么他们可能被那种香气所影响而做优雅的梦。</p><p>尽管如此，我还是体验到了，梦境容易受到入睡前环境的影响。例如，最近我开始一边播放视频一边睡觉了。我用支架把iPad固定在床上，一边看着火车慢慢向海外驶去的视频，一边逐渐沉入睡眠药的效力中而进入梦乡。我持续着这种睡眠循环。</p><p>那么结果怎么样呢？安眠时看的视频，或者说是睡觉时播放出的声音，它们被大脑处理，在梦里出现的概率明显提高了。有一次火车视频突然自动播放切换为主播开包 Pokémon 卡牌的视频。而在梦中，我在百货公司四处寻找 Pokémon 卡，感到筋疲力尽。总的来说更像是噩梦吧。</p><p>不知道为什么我会做这样的梦，所以醒来后，我检查了iPad的历史记录，发现有一个 Pokémon 卡牌开包视频。由于我没有嗅觉，所以听觉刺激可能会对我的梦产生很大的影响。</p><p>然后我尝试了各种方法。首先，我觉得应该在梦中体验那些只有在梦中才能做的事情。也就是，在梦中与二次元角色相遇。当我在梦中与二次元角色交谈时，会觉得「她真的在那里」。那太过理所当然了，以至于我不知道该有多么感激，也不知道现实中的我多么地追求着这番景象...然后，醒来后，我会怀抱着那失去的重要瞬间和她的余渣，然后痛哭流涕。</p><p>因此，我尝试了边播放动画边入睡。然而，这并没有太大的影响，而且让我很难入睡。动画角色的声音透过眼皮传入，吸引着我，让我不由自主地睁开眼睛查看。即使在药物的作用下，也很难入睡，因为动画中的场景转换得太快，固定的形象无法在梦中反映出来。</p><p>在这种情况下，Vtuber的闲聊直播似乎是最佳选择。闲聊直播通常有一定的话题，视频中的角色只是左右摇头，所以只需听声音，无需睁开眼睛。但是，重要的问题是「尴尬」。如果二次元美少女出现在梦中，那当然将是一件让人高兴的事。但实际上，刻意尝试「梦到Vtuber」似乎太像是青春期的行为了。</p><p>在矛盾和挣扎之后，我放弃了。归根结底，她们的声音在入睡时持续听下去实在是太尖锐和愉快了。如果她们真的在梦中出现，相比于开心，尴尬更可能会占上风。一个中年男子每天晚上都做与一名流行主播友好交谈的梦......这实在令人尴尬。这是一件令人伤心的事情。</p><p>最终，我在入睡时通常选择听电子音乐，大多数是Kraftwerk（クラフトワーク）。沉浸在他们演奏的电子声音中，感觉自己就像一台被编程的计算机，感觉非常愉快。顺便说一下，我从未梦到过Kraftwerk。恐怕声音比乐曲更重要。</p><p>换个话题，前不久有人提出了「你要不要制作超天酱的香水？」的问题。有人解释说，香水是让人高兴的东西，而且很多人都会喜欢。如果粉丝希望的话，当然我也想做，但如前所述，我没有嗅觉。这样一来，我无法监督商品的制作，也不能保证基本构思的完整性。但我会尽力解决这个问题的。</p><p>如果超天酱的香水问世，粉丝们可以沐浴在这种香气中，近距离地感受到超天酱，还可以喷在床上用品之类的上面，仿佛她就在身边一般。当你在这种香气中入睡，也许在梦中就能与这位互联网天使相遇。这真是太好了。</p><p>就像这样，让我们都在梦里找到幸福吧。尽管这有时候很难。晚安。</p><hr><p><img src="'+l+'" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/4b0d74ab9a8d0d51a140d4fa4583d993.jpg" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/191895da1fe7e8415731872c44a4b973.jpg" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【CCP出品的“Mr. VTR”】这是筋肉人（キン肉マン）系列中的超人『Mr. VTR』的珍贵立体模型。与筋肉人一样受欢迎的系列才能够得到立体化的机会，所以这个消息让人非常高兴。机械超人在没有进行战斗的日常生活中，可能会感受到自己的畸形和不便，这让人不禁产生担忧，同时也希望他的设计能够更清晰地展现出这种想法。</p></blockquote>',17);function g(V,x){const r=a("ExternalLinkIcon"),n=a("RouterLink");return c(),_("div",null,[i(" more "),k,e("p",null,[t("原文链接："),e("a",u,[t("第33回／夢コントロール"),o(r)])]),e("blockquote",null,[h,e("p",null,[o(n,{to:"/posts/Translate/nyalra_kb_32.html"},{default:m(()=>[t("【奈亚拉面壁自语】第32回｜闭嘴，在游戏中决一胜负吧！！！【230627】")]),_:1})])]),b])}const N=s(f,[["render",g],["__file","nyalra_kb_33.html.vue"]]);export{N as default};
